class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        app: ElasticsearchApp,
        service: str,
        environment: str = "prod",
        level: int = logging.INFO,
    ) -> None:
        super().__init__(level=level)
        self.app = app
        self.service = service
        self.environment = environment

    def emit(self, record: logging.LogRecord) -> None:
        try:
            fields = {
                "module": record.module,
                "funcName": record.funcName,
                "lineNo": record.lineno,
                "process": record.process,
                "thread": record.thread,
                "pathname": record.pathname,
            }

            trace_id = getattr(record, "trace_id", None)
            span_id = getattr(record, "span_id", None)

            self.app.log_event(
                service=self.service,
                level=record.levelname,
                message=self.format(record),
                environment=self.environment,
                logger_name=record.name,
                trace_id=trace_id,
                span_id=span_id,
                fields=fields,
                timestamp=datetime.fromtimestamp(record.created, tz=timezone.utc).isoformat(),
            )
        except Exception:
            self.handleError(record)


def setup_python_logger(app: ElasticsearchApp, service: str, environment: str = "prod") -> logging.Logger:
    logger = logging.getLogger(service)
    logger.setLevel(logging.INFO)

    if not any(isinstance(h, ElasticsearchLogHandler) for h in logger.handlers):
        es_handler = ElasticsearchLogHandler(app=app, service=service, environment=environment)
        es_handler.setFormatter(logging.Formatter("%(asctime)s %(name)s %(levelname)s %(message)s"))
        logger.addHandler(es_handler)

    if not any(isinstance(h, logging.StreamHandler) for h in logger.handlers):
        stream = logging.StreamHandler(sys.stdout)
        stream.setFormatter(logging.Formatter("%(asctime)s %(name)s %(levelname)s %(message)s"))
        logger.addHandler(stream)

    return logger


def iso_utc(hours_ago: int = 0) -> str:
    return (datetime.now(timezone.utc) - timedelta(hours=hours_ago)).isoformat()


def print_json(data: Any) -> None:
    print(json.dumps(data, indent=2, default=str))


def demo() -> None:
    app = ElasticsearchApp(hosts=["http://localhost:9200"], index_prefix="centralized")
    if not app.ping():
        raise ConnectionError("Unable to connect to Elasticsearch at localhost:9200")

    app.ensure_indices()

    app.index_document(
        title="Centralized Logging Platform",
        content="Elasticsearch enables distributed full-text search and analytics for logs and documents.",
        tags=["logging", "search", "elasticsearch"],
        author="admin",
        metadata={"team": "platform", "priority": "high"},
    )

    app.bulk_index_documents(
        [
            {
                "title": "Search Best Practices",
                "content": "Use analyzers, relevance tuning, and highlighting for better search experiences.",
                "tags": ["search", "relevance"],
                "author": "search-team",
            },
            {
                "title": "Observability Pipeline",
                "content": "Centralized logs improve troubleshooting, auditing, and operational insights.",
                "tags": ["observability", "logging"],
                "author": "ops-team",
            },
        ]
    )

    logger = setup_python_logger(app, service="api-gateway", environment="prod")
    logger.info("API gateway started successfully")
    logger.warning("High response latency detected", extra={"trace_id": "trace-123", "span_id": "span-456"})

    app.bulk_log_events(
        [
            {
                "service": "auth-service",
                "level": "ERROR",
                "message": "Token validation failed",
                "environment": "prod",
                "host": "auth-node-1",
                "fields": {"user_id": "u123", "status_code": 401},
            },
            {
                "service": "billing-service",
                "level": "INFO",
                "message": "Invoice generated",
                "environment": "prod",
                "host": "billing-node-2",
                "fields": {"invoice_id": "inv-987", "amount": 49.99},
            },
            {
                "service": "auth-service",
                "level": "INFO",
                "message": "User login successful",
                "environment": "prod",
                "host": "auth-node-1",
                "fields": {"user_id": "u123"},
            },
        ]
    )

    docs_result = app.search_documents(query="distributed search logging", tags=["logging"])
    logs_result = app.search_logs(query="failed OR latency", environment="prod", start_time=iso_utc(24))
    agg_result = app.aggregate_logs(interval="1h", start_time=iso_utc(24), environment="prod")

    print("DOCUMENT SEARCH RESULTS")
    print_json(docs_result)

    print("LOG SEARCH RESULTS")
    print_json(logs_result)

    print("LOG AGGREGATIONS")
    print_json(agg_result)


if __name__ == "__main__":
    demo()